import{_ as e}from"./chunks/Dashboard_ComputerMaintenance_Dark.DR4f9QTw.js";import{_ as o}from"./chunks/Dashboard_ScriptCards_Dark.C3p9XNNL.js";import{_ as t,c as r,o as s,ae as i}from"./chunks/framework.CM88uqJ3.js";const f=JSON.parse('{"title":"About Dashboards","description":"","frontmatter":{},"headers":[],"relativePath":"dashboards/about.md","filePath":"dashboards/about.md"}'),n={name:"dashboards/about.md"};function l(d,a,h,c,g,u){return s(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="about-dashboards" tabindex="-1">About Dashboards <a class="header-anchor" href="#about-dashboards" aria-label="Permalink to &quot;About Dashboards&quot;">​</a></h1><p>Dashboards in PoshUI are designed for real-time monitoring, KPI visualization, and IT operations management. They provide a high-level overview of system health and metrics using a card-based grid layout.</p><p><img src="'+e+'" alt="Dashboard with PNG Icons"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Card-Based Layout</strong>: Organized grid of information cards that can be categorized and filtered.</li><li><strong>Rich Visualizations</strong>: Built-in support for metric KPIs, charts (Bar, Line, Area, Pie), and data grids.</li><li><strong>Live Refresh</strong>: Cards can execute PowerShell scripts on a schedule to update their values automatically.</li><li><strong>Category Filtering</strong>: Built-in search and filtering to group related cards together.</li><li><strong>Interactive Tools</strong>: ScriptCards allow users to run management tasks directly from the dashboard.</li><li><strong>Export Capabilities</strong>: Export data from DataGridCards to CSV or TXT files.</li><li><strong>PNG Icon Support</strong> <em>(v1.3.0)</em>: Full-color PNG icons on steps, cards, banners, and carousel slides.</li><li><strong>Carousel Banners with PNG Icons</strong> <em>(v1.3.0)</em>: Per-slide PNG icons in clickable carousel banners.</li><li><strong>Dual-Mode Custom Themes</strong> <em>(v1.3.0)</em>: Independent light/dark color palettes with runtime toggle.</li><li><strong>Theme Toggle</strong> <em>(v1.3.0)</em>: Sun/moon button in the title bar for instant theme switching.</li></ul><p><img src="'+o+'" alt="ScriptCards with PNG Icons"></p><h2 id="when-to-use-dashboards" tabindex="-1">When to Use Dashboards <a class="header-anchor" href="#when-to-use-dashboards" aria-label="Permalink to &quot;When to Use Dashboards&quot;">​</a></h2><p>Dashboards are ideal for:</p><ul><li><strong>System Monitoring</strong>: Tracking CPU, memory, disk space, and service status across servers.</li><li><strong>Deployment Tracking</strong>: Monitoring the progress of automated deployments.</li><li><strong>Incident Management</strong>: Displaying active tickets or alerts from monitoring systems.</li><li><strong>Executive KPI Displays</strong>: High-level summaries of infrastructure health.</li></ul><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><p>A PoshUI Dashboard follows this pattern:</p><ol><li><strong>Initialize</strong>: Use <code>New-PoshUIDashboard</code> to start a new definition.</li><li><strong>Define Pages</strong>: Add dashboard pages using <code>Add-UIStep -Type Dashboard</code>.</li><li><strong>Add Components</strong>: Populate pages with <code>Add-UIVisualizationCard</code>, <code>Add-UIScriptCard</code>, or <code>Add-UIBanner</code>.</li><li><strong>Show</strong>: Display the interface using <code>Show-PoshUIDashboard</code>.</li></ol><p>Next: <a href="./creating-dashboards.html">Creating Dashboards</a></p>',13)])])}const P=t(n,[["render",l]]);export{f as __pageData,P as default};
